# TRANSPORTE Fullscreen Patch - instalador independente de arquivo unico
# Uso remoto: iwr -useb <URL-DESTE-ARQUIVO> | iex
param(
    [string]$DiscordRoot = (Join-Path $env:LOCALAPPDATA 'Discord'),
    [string]$InstallRoot = (Join-Path $env:APPDATA 'TransporteFullscreenPatch'),
    [string]$Ac3BuildPath = '',
    [string]$Ac3BuildUrl = 'https://github.com/marcelov2/discordfullscreen/releases/download/electron-37.6.0-ac3/discord-electron-37.6.0-ac3-win-x64.zip',
    [string]$Ac3BuildSha256 = '8682D4269D4F96B2AD309544B6D1506375B840B013631F48D156A3EE00449921',
    [switch]$SkipStartupRepair,
    [switch]$DoNotStartDiscord
)

$ErrorActionPreference = 'Stop'

$discordWasRunning = [bool](Get-Process -Name Discord -ErrorAction SilentlyContinue)
Write-Host '[1/5] Fechando o Discord...'
if ($discordWasRunning) {
    1..25 | ForEach-Object {
        Get-Process -Name Discord -ErrorAction SilentlyContinue |
            Stop-Process -Force -ErrorAction SilentlyContinue
        Start-Sleep -Milliseconds 200
    }
}
if (Get-Process -Name Discord -ErrorAction SilentlyContinue) {
    throw 'O Discord nao pode ser encerrado. Execute o PowerShell como administrador e tente novamente.'
}

$payloadBase64 = ''
$payloadJson = [Text.Encoding]::UTF8.GetString([Convert]::FromBase64String($payloadBase64))
$payload = $payloadJson | ConvertFrom-Json
$utf8NoBom = New-Object Text.UTF8Encoding($false)

Write-Host '[2/5] Preparando o instalador...'
New-Item -ItemType Directory -Force -Path $InstallRoot | Out-Null
foreach ($property in $payload.PSObject.Properties) {
    $destination = Join-Path $InstallRoot $property.Name
    [IO.File]::WriteAllText($destination, [string]$property.Value, $utf8NoBom)
}

. (Join-Path $InstallRoot 'patch-common.ps1')
$apps = @(Get-HarborDiscordApps -DiscordRoot $DiscordRoot)
if ($apps.Count -eq 0) { throw "Nenhuma instalacao do Discord encontrada em $DiscordRoot" }

$archivePath = Join-Path $InstallRoot 'discord-electron-37.6.0-ac3-win-x64.zip'
Write-Host '[3/5] Obtendo e validando a build AC3/E-AC3...'
if ($Ac3BuildPath) {
    $resolvedSource = (Resolve-Path -LiteralPath $Ac3BuildPath).Path
    if ($resolvedSource -ne $archivePath) {
        Copy-Item -LiteralPath $resolvedSource -Destination $archivePath -Force
    }
} elseif (-not (Test-Path -LiteralPath $archivePath -PathType Leaf) -or
    -not (Test-HarborFileSha256 -Path $archivePath -ExpectedSha256 $Ac3BuildSha256)) {
    $temporaryArchive = "$archivePath.download"
    Remove-Item -LiteralPath $temporaryArchive -Force -ErrorAction SilentlyContinue
    Invoke-WebRequest -UseBasicParsing -Uri $Ac3BuildUrl -OutFile $temporaryArchive
    if (-not (Test-HarborFileSha256 -Path $temporaryArchive -ExpectedSha256 $Ac3BuildSha256)) {
        $actualHash = Get-HarborFileSha256 -Path $temporaryArchive
        Remove-Item -LiteralPath $temporaryArchive -Force -ErrorAction SilentlyContinue
        throw "SHA-256 invalido para a build AC3. Esperado $Ac3BuildSha256, recebido $actualHash"
    }
    Move-Item -LiteralPath $temporaryArchive -Destination $archivePath -Force
}

$backupRoot = Join-Path $InstallRoot 'runtime-backups'
Install-HarborAc3RuntimeIntoApp -AppDir $apps[0].FullName -ArchivePath $archivePath -BackupRoot $backupRoot -ExpectedSha256 $Ac3BuildSha256 | Out-Null

Write-Host '[4/5] Instalando o fullscreen...'
$patcher = Join-Path $InstallRoot 'patcher.js'
$installed = Install-HarborPatchIntoApp -AppDir $apps[0].FullName -PatcherPath $patcher 6>$null
if (-not $installed) {
    throw 'Nao foi possivel instalar na versao mais recente do Discord. Veja os avisos acima.'
}

if (-not $SkipStartupRepair) {
    $runKey = 'HKCU:\Software\Microsoft\Windows\CurrentVersion\Run'
    $repair = Join-Path $InstallRoot 'repair.ps1'
    $runCommand = "powershell.exe -NoProfile -ExecutionPolicy Bypass -WindowStyle Hidden -File `"$repair`" -DiscordRoot `"$DiscordRoot`" -InstallRoot `"$InstallRoot`""
    New-Item -Path $runKey -Force | Out-Null
    Remove-ItemProperty -Path $runKey -Name 'HarborFullscreenPatchRepair' -ErrorAction SilentlyContinue
    Set-ItemProperty -Path $runKey -Name 'TransporteFullscreenPatchRepair' -Value $runCommand
}

$discordExe = Join-Path $apps[0].FullName 'Discord.exe'
if (-not $DoNotStartDiscord -and (Test-Path -LiteralPath $discordExe -PathType Leaf)) {
    Write-Host '[5/5] Abrindo o Discord AC3...'
    Start-Process -FilePath $discordExe -RedirectStandardOutput 'NUL' -RedirectStandardError '\\.\NUL'
}

Write-Host 'Finalizado. AC3/E-AC3 e fullscreen instalados.' -ForegroundColor Green
Write-Warning 'O Krisp oficial fica indisponivel porque a build personalizada nao possui assinatura digital da Discord. Use a supressao de ruido Padrao.'
Start-Sleep -Milliseconds 800
exit 0
